163→            {
164→                const int32_t rhs_value0 = (int8_t)*rhs_ptr_0;
165→                const int32_t rhs_value1 = (int8_t)*rhs_ptr_1;
166→                const int32_t rhs_value2 = (int8_t)*rhs_ptr_2;
167→                const int32_t lhs_value = (int8_t)*lhs_ptr + lhs_offset;
168→
169→                res00 += lhs_value * rhs_value0;
170→                res01 += lhs_value * rhs_value1;
171→                res02 += lhs_value * rhs_value2;
172→
173→                ++rhs_ptr_0;
174→                ++rhs_ptr_1;
175→                ++rhs_ptr_2;
176→                ++lhs_ptr;
177→            }
178→            // Quantize down
179→            res00 = nn_requantize(res00, *dst_multiplier++, *dst_shift++);
180→            res01 = nn_requantize(res01, *dst_multiplier++, *dst_shift++);
181→            res02 = nn_requantize(res02, *dst_multiplier++, *dst_shift++);
182→
183→            // Add offset
184→            res00 += dst_offset;
185→            res01 += dst_offset;
186→            res02 += dst_offset;
187→
188→            // Clamp the result
189→            res00 = MAX(res00, activation_min);
190→            res00 = MIN(res00, activation_max);
191→            res01 = MAX(res01, activation_min);
192→            res01 = MIN(res01, activation_max);
193→            res02 = MAX(res02, activation_min);
194→            res02 = MIN(res02, activation_max);
195→
196→            *dst = (int8_t)res00;
197→            *(dst + address_offset) = (int8_t)res01;
198→            *(dst + 2 * address_offset) = (int8_t)res02;
199→            dst += 3 * address_offset;
200→
201→            rhs += 3 * rhs_cols;
202→        }
203→
204→        const int loop_cnt = rhs_rows % 3;
205→
206→        for (int32_t i_loop_cnt = 0; i_loop_cnt < loop_cnt; i_loop_cnt++)
207→        {
208→            const int8_t *lhs_ptr = &lhs[0];
209→            const int8_t *rhs_ptr = &rhs[0];
210→
211→            int32_t res00 = 0;
212→            if (bias)
213→            {
214→                res00 = *bias++;
