216→
217→            for (int32_t rhs_cols_idx = 0; rhs_cols_idx < rhs_cols; ++rhs_cols_idx)
218→            {
219→                int32_t rhs_value0 = (int8_t)rhs_ptr[0];
220→                int32_t lhs_value = (int8_t)lhs_ptr[0] + lhs_offset;
221→
222→                res00 += lhs_value * rhs_value0;
