 20→#include "internal_nn_math.h"
 21→
 22→int32_t nn_vec_mat_mult_t_s8(const q7_t *lhs,
 23→                             const q7_t *rhs,
 24→                             const q31_t *bias,
 25→                             q7_t *dst,
 26→                             const int32_t lhs_offset,   //value is in the range of [-127, 128]
 27→                             const int32_t rhs_offset,   //value is in the range of [-127, 128]
 28→                             const int32_t dst_offset,   //value is in the range of [-128, 127]
 29→                             const int32_t dst_multiplier,
 30→                             const int32_t dst_shift,
 31→                             const int32_t rhs_cols,
 32→                             const int32_t rhs_rows,
 33→                             const int32_t activation_min,
 34→                             const int32_t activation_max)
 35→{
 36→#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
 37→    long vl;
 38→    long dst_shift2 = 30 - dst_shift;
 39→
 40→    for (int32_t rhs_rows_idx = 0; rhs_rows_idx <= (rhs_rows - 2); rhs_rows_idx += 2)
 41→    {
 42→        const q7_t *lhs_ptr = &lhs[0];
 43→        const q7_t *rhs_ptr = &rhs[0];
 44→        const q7_t *rhs_ptr2 = &rhs[rhs_cols];
 45→        vl = __riscv_vsetvl_e32m8(rhs_cols);
 46→        vint32m8_t vResult1 = __riscv_vundefined_i32m8(),
 47→                   vResult2 = __riscv_vundefined_i32m8();
 48→        vResult1 = __riscv_vand(vResult1, 0, vl);     //for keeping 1st vwmacc results
 49→        vResult2 = __riscv_vand(vResult2, 0, vl);     //for keeping 2nd vwmacc results
 50→
 51→        long rhs_cols2 = rhs_cols;
 52→        while(rhs_cols2 > 0)
 53→        {
 54→            vl = __riscv_vsetvl_e8m2(rhs_cols2);
 55→            vint8m2_t vLhs_i8 = __riscv_vle8_v_i8m2(lhs_ptr, vl);                   //*lhs_ptr
 56→            vint8m2_t vRhs_i8 = __riscv_vle8_v_i8m2(rhs_ptr, vl);                   //*rhs_ptr
 57→            vint8m2_t vRhs2_i8 = __riscv_vle8_v_i8m2(rhs_ptr2, vl);                 //*rhs_ptr2
 58→            vl = __riscv_vsetvl_e16m4(rhs_cols2);
 59→            vint16m4_t vLhs_i16 = __riscv_vsext_vf2(vLhs_i8, vl);
 60→            vint16m4_t vRhs_i16 = __riscv_vsext_vf2(vRhs_i8, vl);
 61→            vint16m4_t vRhs2_i16 = __riscv_vsext_vf2(vRhs2_i8, vl);
 62→            vLhs_i16 = __riscv_vadd(vLhs_i16, lhs_offset, vl);    //*lhs_ptr + lhs_offset
 63→            vRhs_i16 = __riscv_vadd(vRhs_i16, rhs_offset, vl);    //*rhs_ptr + rhs_offset
 64→            vRhs2_i16 = __riscv_vadd(vRhs2_i16, rhs_offset, vl);  //*rhs_ptr2 + rhs_offset
 65→            vResult1 = __riscv_vwmacc(vResult1, vLhs_i16, vRhs_i16, vl);
 66→            vResult2 = __riscv_vwmacc(vResult2, vLhs_i16, vRhs2_i16, vl);
 67→            lhs_ptr += vl;
 68→            rhs_ptr += vl;
 69→            rhs_ptr2 += vl;
 70→            rhs_cols2 -= vl;
 71→        }
 72→
 73→        vl = __riscv_vsetvl_e32m1(1);
 74→        vint32m1_t vZero = __riscv_vundefined_i32m1();
 75→        vZero = __riscv_vand(vZero, 0, vl);
 76→
 77→        //note the avl here to make sure the length to be reducted into sum is correct
 78→        vl = __riscv_vsetvl_e32m8(rhs_cols);
 79→        vint32m1_t vRedsum1_i32 = __riscv_vundefined_i32m1();
