#include "internal_nn_math.h"

int32_t nn_vec_mat_mult_t_s8(const q7_t *lhs,
                             const q7_t *rhs,
                             const q31_t *bias,
                             q7_t *dst,
                             const int32_t lhs_offset,   //value is in the range of [-127, 128]
                             const int32_t rhs_offset,   //value is in the range of [-127, 128]
                             const int32_t dst_offset,   //value is in the range of [-128, 127]
                             const int32_t dst_multiplier,
                             const int32_t dst_shift,
                             const int32_t rhs_cols,
                             const int32_t rhs_rows,
                             const int32_t activation_min,
                             const int32_t activation_max)
{
#if defined(ENA_VEC_ISA) && (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
    long vl;
    long dst_shift2 = 30 - dst_shift;

    for (int32_t rhs_rows_idx = 0; rhs_rows_idx <= (rhs_rows - 2); rhs_rows_idx += 2)
    {
        const q7_t *lhs_ptr = &lhs[0];
        const q7_t *rhs_ptr = &rhs[0];
        const q7_t *rhs_ptr2 = &rhs[rhs_cols];
        vl = __riscv_vsetvl_e32m8(rhs_cols);
        vint32m8_t vResult1 = __riscv_vundefined_i32m8(),
                   vResult2 = __riscv_vundefined_i32m8();
        vResult1 = __riscv_vand(vResult1, 0, vl);     //for keeping 1st vwmacc results
        vResult2 = __riscv_vand(vResult2, 0, vl);     //for keeping 2nd vwmacc results

        long rhs_cols2 = rhs_cols;
        while(rhs_cols2 > 0)
        {
            vl = __riscv_vsetvl_e8m2(rhs_cols2);
            vint8m2_t vLhs_i8 = __riscv_vle8_v_i8m2(lhs_ptr, vl);                   //*lhs_ptr
            vint8m2_t vRhs_i8 = __riscv_vle8_v_i8m2(rhs_ptr, vl);                   //*rhs_ptr
            vint8m2_t vRhs2_i8 = __riscv_vle8_v_i8m2(rhs_ptr2, vl);                 //*rhs_ptr2
            vl = __riscv_vsetvl_e16m4(rhs_cols2);
            vint16m4_t vLhs_i16 = __riscv_vsext_vf2(vLhs_i8, vl);
            vint16m4_t vRhs_i16 = __riscv_vsext_vf2(vRhs_i8, vl);
            vint16m4_t vRhs2_i16 = __riscv_vsext_vf2(vRhs2_i8, vl);
            vLhs_i16 = __riscv_vadd(vLhs_i16, lhs_offset, vl);    //*lhs_ptr + lhs_offset
            vRhs_i16 = __riscv_vadd(vRhs_i16, rhs_offset, vl);    //*rhs_ptr + rhs_offset
            vRhs2_i16 = __riscv_vadd(vRhs2_i16, rhs_offset, vl);  //*rhs_ptr2 + rhs_offset
            vResult1 = __riscv_vwmacc(vResult1, vLhs_i16, vRhs_i16, vl);
            vResult2 = __riscv_vwmacc(vResult2, vLhs_i16, vRhs2_i16, vl);
            lhs_ptr += vl;
            rhs_ptr += vl;
            rhs_ptr2 += vl;
            rhs_cols2 -= vl;
        }

        vl = __riscv_vsetvl_e32m1(1);
        vint32m1_t vZero = __riscv_vundefined_i32m1();
        vZero = __riscv_vand(vZero, 0, vl);

        //note the avl here to make sure the length to be reducted into sum is correct
        vl = __riscv_vsetvl_e32m8(rhs_cols);
        vint32m1_t vRedsum1_i32 = __riscv_vundefined_i32m1();
        vint32m1_t vRedsum2_i32 = __riscv_vundefined_i32m1();
        vRedsum1_i32 = __riscv_vredsum(vResult1, vZero, vl);
        vRedsum2_i32 = __riscv_vredsum(vResult2, vZero, vl);

        vl = __riscv_vsetvl_e32m1(2);
        vRedsum1_i32 = __riscv_vslideup(vRedsum1_i32, vRedsum2_i32, 1, vl);

        if(bias != NULL)
        {
            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
            vRedsum1_i32 = __riscv_vadd(vRedsum1_i32, vBias, vl);
            bias += vl;
        }

        // re-quantize
        vint64m2_t vWmul_r0 = __riscv_vwmul(vRedsum1_i32, dst_multiplier, vl);
        vRedsum1_i32 = __riscv_vnsra(vWmul_r0, dst_shift2, vl);
        vRedsum1_i32 = __riscv_vssra(vRedsum1_i32, 1, __RISCV_VXRM_RNU, vl);

        vRedsum1_i32 = __riscv_vadd(vRedsum1_i32, dst_offset, vl);

        // Clamp the result
        vRedsum1_i32 = __riscv_vmax(vRedsum1_i32, activation_min, vl);
        vRedsum1_i32 = __riscv_vmin(vRedsum1_i32, activation_max, vl);

        //narrowing and store the results
        vl = __riscv_vsetvl_e16mf2(vl);
        vint16mf2_t vRedsum1_i16 = __riscv_vnsra(vRedsum1_i32, 0, vl);
        vl = __riscv_vsetvl_e8mf4(vl);
        vint8mf4_t vRedsum1_i8 = __riscv_vnsra(vRedsum1_i16, 0, vl);
        __riscv_vse8(dst, vRedsum1_i8, vl);
        dst += vl;
        rhs += 2 * rhs_cols;
    }

    if (rhs_rows & 1)
    {
        const q7_t *lhs_ptr = &lhs[0];
        const q7_t *rhs_ptr = &rhs[0];

        vl = __riscv_vsetvl_e32m1(1);

